foreach ($screen in $screens) {
    $name = $screen[0]
    $imgUrl = $screen[1]
    $htmlUrl = $screen[2]
    
    # Check if file already exists to skip redundant downloads
    if (!(Test-Path "stitch-assets/$name.png")) {
        Write-Host "Downloading $name image..."
        & curl.exe -L "$imgUrl" -o "stitch-assets/$name.png"
    }
    if (!(Test-Path "stitch-assets/$name.html")) {
        Write-Host "Downloading $name code..."
        & curl.exe -L "$htmlUrl" -o "stitch-assets/$name.html"
    }
}
